.sidebar.toggled[data-panel='scores'] * {
  -webkit-touch-callout: none;
  -webkit-user-select: none;
  -khtml-user-select: none;
  -moz-user-select: none;
  -ms-user-select: none;
  user-select: none;
}
.sidebar.toggled[data-panel='scores'] .header-score-title {
  text-align: center;
  padding: 7px;
  border-bottom: 1px solid #c7c7c7;
}
.sidebar.toggled[data-panel='scores'] .header-score-title [data-action='close-scores'] {
  right: 13px;
  position: absolute;
  font-size: 14px;
  text-decoration: underline;
  color: #ff2b2b;
  cursor: pointer;
  top: 2px;
}
.sidebar.toggled[data-panel='scores'] .content-list {
  overflow: auto;
  overflow-x: hidden;
}
.sidebar.toggled[data-panel='scores'] .content-list .loader-parent {
  text-align: center;
  margin-top: 18px;
}
.sidebar.toggled[data-panel='scores'] .content-list .header-d.close-group:after {
  content: "\f106";
}
.sidebar.toggled[data-panel='scores'] .content-list .header-d {
  background-color: #292929;
  padding: 5px 4px;
  height: 30px;
  width: 100%;
  float: left;
  cursor: pointer;
  border-bottom: 1px solid #636363;
  position: relative;
}
.sidebar.toggled[data-panel='scores'] .content-list .header-d:after {
  font-family: 'FontAwesome';
  content: "\f107";
  position: absolute;
  color: white;
  font-size: 19px;
  top: 2px;
  right: 12px;
}
.sidebar.toggled[data-panel='scores'] .content-list .header-d span {
  color: white ;
  font-size: 14px;
}
.sidebar.toggled[data-panel='scores'] .content-list .refresh-score {
  text-decoration: none;
  -webkit-animation: refresh-effect 1s;
  /* Safari 4.0 - 8.0 */
  -webkit-animation-iteration-count: 1;
  /* Safari 4.0 - 8.0 */
  animation: refresh-effect 1s;
  animation-iteration-count: 6;
}
@-webkit-keyframes refresh-effect {
  from {
    background-color: white;
  }
  to {
    background-color: #f5ff9d;
  }
}
.sidebar.toggled[data-panel='scores'] .content-list .img-logo {
  width: 20px;
  height: 16px;
  margin-right: 4px;
  margin-left: 0px;
  padding-right: 0px;
  vertical-align: middle;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] {
  height: auto;
  width: 100%;
  float: left;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item {
  height: auto;
  background: white;
  border: 1px solid #cecece;
  cursor: pointer;
  padding: 4px 0px;
  padding-top: 0px;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .time-channel {
  height: 22px;
  width: 100%;
  overflow: hidden;
  padding-top: 2px;
  background-color: #eeeeee;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .time-channel .time {
  font-family: "Cabin", sans-serif;
  float: left;
  padding-left: 2px;
  color: #474747;
  padding-top: 1px;
  font-size: 12px;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .time-channel .channel {
  font-family: "Cabin", sans-serif;
  float: right;
  padding-right: 2px;
  color: #00843b;
  font-size: 12px;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .rank {
  color: green;
  margin-right: 1px;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-1 {
  height: 20px;
  width: 100%;
  overflow: hidden;
  padding: 1px 2px;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-1 img {
  width: 20px !important;
  height: 16px !important;
  margin-right: 4px !important;
  margin-left: 0px !important;
  padding-right: 0px !important;
  vertical-align: middle !important;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-1 span,
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-1 img {
  display: inline-block;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-1 span {
  font-size: 12px;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-1 span.score {
  float: right;
  font-size: 13px !important;
  padding-top: 2px;
  font-family: 'Quantico', sans-serif !important;
  font-size: 0.9em !important;
  letter-spacing: 1px !important;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-2 {
  height: 20px;
  width: 100%;
  overflow: hidden;
  padding: 1px 2px;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-2 img {
  width: 20px !important;
  height: 16px !important;
  margin-right: 4px !important;
  margin-left: 0px !important;
  padding-right: 0px !important;
  vertical-align: middle !important;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-2 span,
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-2 img {
  display: inline-block;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-2 span {
  font-size: 12px;
}
.sidebar.toggled[data-panel='scores'] .content-list div[data-list] .item .team-2 span.score {
  float: right;
  font-size: 13px !important;
  padding-top: 2px;
  font-family: 'Quantico', sans-serif !important;
  font-size: 0.9em !important;
  letter-spacing: 1px !important;
}
.sidebar.toggled[data-panel='scores'] .svg-loader {
  position: relative;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  z-index: 1040;
  background-color: rgba(190, 190, 190, 0.6);
}
.sidebar.toggled[data-panel='scores'] .svg-loader .content-svg {
  position: absolute;
  top: initial;
  left: initial;
  transform: translate(30%, 50%);
  background-color: white;
  text-align: center;
  height: 130px;
  padding-top: 30px;
  border: 1px solid #6d6d6d;
  width: 205px;
}
@media (max-width: 767px) {
  .sidebar.toggled[data-panel='scores'] {
    right: 0;
    opacity: 1 !important;
    z-index: 2000;
    width: 100%;
    max-width: 100%;
  }
}
